package com.museumheist.game.character;public final class CharacterConfig{private final String id,name,description,previewAsset,homeAsset,gameAsset,styleTag;private final float speedMultiplier,pickupRadiusBonus,collisionScale;private final int primaryColor,secondaryColor,accentColor,darkColor,skinColor,pantsColor,shoeColor,variant;public CharacterConfig(String id,String name,String description,String preview,String home,String game,String style,float speed,float pickup,float collision,int primary,int secondary,int accent,int dark,int skin,int pants,int shoe,int variant){this.id=id;this.name=name;this.description=description;previewAsset=preview;homeAsset=home;gameAsset=game;styleTag=style;speedMultiplier=speed;pickupRadiusBonus=pickup;collisionScale=collision;primaryColor=primary;secondaryColor=secondary;accentColor=accent;darkColor=dark;skinColor=skin;pantsColor=pants;shoeColor=shoe;this.variant=variant;}public String getId(){return id;}public String getName(){return name;}public String getDescription(){return description;}public String getStyleTag(){return styleTag;}public float getSpeedMultiplier(){return speedMultiplier;}public float getPickupRadiusBonus(){return pickupRadiusBonus;}public float getCollisionScale(){return collisionScale;}public int getPrimaryColor(){return primaryColor;}public int getSecondaryColor(){return secondaryColor;}public int getAccentColor(){return accentColor;}public int getDarkColor(){return darkColor;}public int getSkinColor(){return skinColor;}public int getPantsColor(){return pantsColor;}public int getShoeColor(){return shoeColor;}public int getVariant(){return variant;}}
